try {
  let data = $input.item.json.text || $input.item.json.output || $input.item.json.content;
  if (typeof data === 'string' && data.startsWith('```json')) {
    data = data.replace(/```json/g, '').replace(/```/g, '');
  }
  const parsed = typeof data === 'string' ? JSON.parse(data) : data;
  // Forçar status e tipo para garantir as regras de negócio
  parsed.status = 'pending';
  parsed.type = 'saida';
  return parsed;
} catch(e) {
  return { date: '', description: 'Erro de Leitura OCR', amount: 0, type: 'saida', account: '', status: 'pending' };
}
